package io.coderf.arklab.common.utils.download;import android.Manifest;import android.app.Activity;import android.content.Context;import android.content.pm.PackageManager;import android.os.Build;import androidx.annotation.NonNull;import androidx.core.app.ActivityCompat;import androidx.core.content.ContextCompat;import java.util.HashMap;import java.util.Map;import java.util.WeakHashMap;import java.util.function.Supplier;import io.reactivex.rxjava3.core.Observable;/** * 下载/更新模块的存储权限辅助类。 * <p> * Android 10（API 29）及以下写入外部存储需要 {@link Manifest.permission#WRITE_EXTERNAL_STORAGE}， * Android 11+ 使用应用专属目录（{@link io.coderf.arklab.common.utils.common.FileUtil#getDefaultDownloadDir}）无需此权限。 * <p> * <b>自动重试机制</b>：调用 {@link #deferWithStoragePermission} 或 {@link #requestPermission} 时， * 若权限尚未授予会先弹出系统授权框；用户同意后 {@link #dispatchPermissionResult} 会执行挂起的下载任务， * 无需用户再次点击。继承 {@link io.coderf.arklab.common.base.BaseActivity} 的页面已自动转发权限结果。 * <p> * 业务方自定义更新 Dialog 时，可在「立即更新」按钮中调用： * <pre>{@code * DownloadPermissionHelper.requestPermission(activity, REQUEST_CODE_UPDATE, onGranted, onDenied); * }</pre> * * @author fz * @see DownloadManager * @see UpdateManager */public final class DownloadPermissionHelper {    /** 普通文件下载权限请求码，对应 {@link DownloadManager} */    public static final int REQUEST_CODE_DOWNLOAD = 0x01;    /** APK 更新权限请求码，对应 {@link UpdateManager} 与 {@link io.coderf.arklab.common.utils.download.listener.ApkUpdateListener} */    public static final int REQUEST_CODE_UPDATE = 0x02;    private static final Object LOCK = new Object();    /** Activity → (requestCode → 授权后继续执行的任务)，WeakReference 避免泄漏 */    private static final Map<Activity, Map<Integer, Runnable>> PENDING_ACTIONS = new WeakHashMap<>();    private DownloadPermissionHelper() {    }    /**     * 是否已具备写入存储所需权限。     * API 30+ 始终返回 {@code true}（使用应用专属目录）。     */    public static boolean hasStoragePermission(@NonNull Context context) {        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {            return true;        }        return ContextCompat.checkSelfPermission(context, Manifest.permission.WRITE_EXTERNAL_STORAGE)                == PackageManager.PERMISSION_GRANTED;    }    /**     * 包装 Observable：无权限时挂起任务，授权后自动订阅 {@code supplier} 提供的下载流。     *     * @param activity    用于申请权限的 Activity     * @param requestCode {@link #REQUEST_CODE_DOWNLOAD} 或 {@link #REQUEST_CODE_UPDATE}     * @param supplier    实际下载 Observable 工厂（仅在权限就绪或授权后调用）     */    public static <T> Observable<T> deferWithStoragePermission(@NonNull Activity activity, int requestCode,                                                               @NonNull Supplier<Observable<T>> supplier) {        return Observable.defer(() -> {            if (hasStoragePermission(activity)) {                return supplier.get();            }            return Observable.create(emitter -> requestPermission(activity, requestCode,                    () -> supplier.get().subscribe(emitter::onNext, emitter::onError, emitter::onComplete),                    emitter::onError));        });    }    /**     * 在 Activity 的 {@code onRequestPermissionsResult} 中调用，触发挂起的下载/更新任务。     *     * @return {@code true} 表示 requestCode 属于本模块并已处理     */    public static boolean dispatchPermissionResult(@NonNull Activity activity, int requestCode,                                                   @NonNull int[] grantResults) {        if (requestCode != REQUEST_CODE_DOWNLOAD && requestCode != REQUEST_CODE_UPDATE) {            return false;        }        if (grantResults.length > 0 && grantResults[0] == PackageManager.PERMISSION_GRANTED) {            Runnable pending = pollPending(activity, requestCode);            if (pending != null) {                pending.run();            }        } else {            clearPending(activity, requestCode);        }        return true;    }    /**     * 申请存储权限并在授权后执行 {@code onGranted}。     * 已有权限时同步执行 {@code onGranted}，不弹窗。     *     * @param onDenied 用户拒绝授权时的回调（通常 Toast 提示）     */    public static void requestPermission(@NonNull Activity activity, int requestCode,                                         @NonNull Runnable onGranted,                                         @NonNull io.reactivex.rxjava3.functions.Consumer<Throwable> onDenied) {        if (hasStoragePermission(activity)) {            onGranted.run();            return;        }        enqueuePending(activity, requestCode, onGranted);        ActivityCompat.requestPermissions(activity,                new String[]{Manifest.permission.WRITE_EXTERNAL_STORAGE}, requestCode);    }    private static void enqueuePending(@NonNull Activity activity, int requestCode, @NonNull Runnable action) {        synchronized (LOCK) {            PENDING_ACTIONS.computeIfAbsent(activity, ignored -> new HashMap<>())                    .put(requestCode, action);        }    }    private static Runnable pollPending(@NonNull Activity activity, int requestCode) {        synchronized (LOCK) {            Map<Integer, Runnable> actions = PENDING_ACTIONS.get(activity);            if (actions == null) {                return null;            }            Runnable pending = actions.remove(requestCode);            if (actions.isEmpty()) {                PENDING_ACTIONS.remove(activity);            }            return pending;        }    }    private static void clearPending(@NonNull Activity activity, int requestCode) {        synchronized (LOCK) {            Map<Integer, Runnable> actions = PENDING_ACTIONS.get(activity);            if (actions == null) {                return;            }            actions.remove(requestCode);            if (actions.isEmpty()) {                PENDING_ACTIONS.remove(activity);            }        }    }}